var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"크윽...... 분하다......","JPN":"くうっ……悔しい……","ENG":"Gah... How infuriating!","TWN":"呃……好氣啊……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"성야의 저주를 전하지 못하고 여기서 쓰러지다니......","JPN":"聖夜の呪いを伝えられずに、ここで倒れるとは……","ENG":"I fell before I got to spread the Curse of the Holy Night...","TWN":"我都沒來得及下星夜的詛咒，竟然就在這裡倒下去了……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"스미스 병장...... 부디 내 뒤를 이어 임무를 완수해 주기 바란다......!","JPN":"スミス兵長……どうか本官の代わりに任務を完遂してくれ……！","ENG":"Sergeant Smith... Please carry on with the mission for me...","TWN":"史密斯兵長……一定要替我完成任務……！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"깨꼬닥~","JPN":"コケコッコー。","ENG":"Ugh.","TWN":"暈厥~"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L8_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"한소림 님이 쓰러졌슴다!","JPN":"ハネダ・ミズキ様が倒れたっす！","ENG":"Ms. Sorim is down, ma'am!","TWN":"韓小姐暈倒了！"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"혹시...... 죽은 거야?","JPN":"まさか……死んじゃったの？","ENG":"Is she... dead?","TWN":"不會是……死了吧？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"새근새근......","JPN":"すやすや……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"걱정 마시길. 평소보다 더 활발하게 움직이느라 기력이 다해 잠든 것으로 보입니다.","JPN":"心配しないでください。たくさん動いたので気力を使い果たし、眠ってしまったようです。","ENG":"Don't worry. She moved so vigorously that she's put herself to sleep.","TWN":"不用擔心，應該是因為比平時活躍，所以精疲力盡昏睡過去了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"다른 희생자 분들처럼요.","JPN":"他の犠牲者のように。","ENG":"Just like the other victims.","TWN":"就像其他受害者一樣。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 이제 남은 건 저 녀석뿐이네.","JPN":"じゃあ、残ったのはあいつだけね。","ENG":"Then, the only one left is him.","TWN":"那麼現在，就只剩下那個傢伙了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"깡촌에 불려 온 걸로도 모자라서 야밤에 생고생을 하게 만들다니, 각오는 됐겠지?","JPN":"ド田舎に呼んだだけじゃ飽き足らず、真夜中にこんな苦労させるなんて。覚悟はできてるわよね？","ENG":"I was already unhappy being dragged here, and then you made me stay up all night for this crap. You'd better be ready for my wrath.","TWN":"來到這個窮鄉僻壤已經讓我受夠了，大半夜的還折騰我，你準備好付出代價了吧？"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"이런, 이런......","JPN":"おやおや……","ENG":"Well, well...","TWN":"沒想到啊……"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아무래도 제가 여러분의 실력을 너무 얕본 모양이네요.","JPN":"僕が皆さんを過小評価していたようですね。","ENG":"I think I have underestimated you.","TWN":"看來我是低估了各位的實力。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"여러분들을 모두 성야의 저주 속으로 초대하려면 지금 같은 방법으론 힘들겠어요.","JPN":"皆さんを呪いの中に招待するには、今の方法では難しそうです。","ENG":"I don't think I can invite all of you into the Curse of the Holy Night, doing this.","TWN":"想用這種方法把各位都請到星夜的詛咒裡是不太可能了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"뭔가...... 지금보다 좀 더 극적인 이벤트가 필요할 것 같군요.","JPN":"何か……今よりもっと劇的なイベントが必要なのですが。","ENG":"I think... I need a more drastic method.","TWN":"看來……需要準備比這個更有戲劇性的驚喜了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"극적인 이벤트?","JPN":"劇的なイベント？","ENG":"A more drastic method?","TWN":"更有戲劇性的驚喜？"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"네, 기대하셔도 좋을 겁니다.","JPN":"はい、期待してもいいですよ。","ENG":"Yes, and you can look forward to it.","TWN":"是的，敬請期待。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그럼 전 준비를 위해 잠시 물러나도록 하죠.","JPN":"では僕は準備があるので、失礼させていただきます。","ENG":"Now, I'll have to leave you for a while to prepare it.","TWN":"那我暫且退避，為大家做準備去了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"어딜 도망가려고? 거기 서!","JPN":"逃げる気！？　待ちなさい！","ENG":"Where do you think you're going? Stop right there!","TWN":"還想跑？站住！"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"위험해요, 실비아 씨! 멈춰요!","JPN":"シルビアさん、危ない！","ENG":"Sylvia, don't! It's too dangerous!","TWN":"危險，希爾維亞小姐！不要去！"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"콜록! 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 천장이 무너졌어?","JPN":"な、何なの？　天井が崩れた？","ENG":"H-huh? The ceiling just collapsed!","TWN":"天、天花板居然塌了？"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네, 선배가 퇴각하면서 기둥을 잘라 놓은 모양이네요.","JPN":"はい、先輩が柱を切断して逃げたようです。","ENG":"Yes. Shiyoon must have cut at the beams as he retreated.","TWN":"是的，應該是前輩撤退的時候把柱子都弄斷了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"큭......! 저런 손바닥만 한 구멍으로 어떻게 저렇게 요리조리 빠져나가는 거야?!","JPN":"くっ……！　あんな小さな穴から、どうしてあちこち移動できるわけ！？","ENG":"Gah, how did he get away through such a tiny hole? It's not any bigger than my palm!","TWN":"咳……！到底是怎麼從那種巴掌大的孔裡逃出去的？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"베로니카 씨, 선배 모습은 안 보이세요?","JPN":"ベロニカさん、先輩の姿は見当たりませんか？","ENG":"Veronica, do you see Shiyoon anywhere?","TWN":"貝洛妮卡，前輩呢？"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"네. 천장이 무너질 때를 마지막으로 흔적도 없이 사라졌습니다.","JPN":"はい。天井が崩れた瞬間、痕跡も残さずに消えました。","ENG":"No. He disappeared when the ceiling collapsed.","TWN":"天花板塌下來的時候，他就已經不見蹤影了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"아무래도 이번에도 놓친 것 같군요.","JPN":"やはり今回も逃したようです。","ENG":"I'm afraid we lost him again.","TWN":"這次還是讓他跑了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"subtitle","speaker":null,"text":{"KOREA":"네번째 희생자: <color=#ffd34c>한소림</color>","JPN":"4人目の犠牲者：<color=#ffd34c>ハネダ・ミズキ</color>","ENG":"Victim 4: <color=#ffd34c>Han Sorim</color>","TWN":"第四個犧牲者：<color=#ffd34c>韓蕭林</color>"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"subtitle","speaker":null,"text":{"KOREA":"남은 생존자: <color=#ffd34c>6명</color>","JPN":"残りの生存者：<color=#ffd34c>6人</color>","ENG":"Remaining survivors: <color=#ffd34c>6</color>","TWN":"生存者：<color=#ffd34c>6名</color>"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};